import { Component, afterNextRender, computed, inject, signal } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { AXPlatform, AXThemeMode } from '@acorex/core/platform';

@Component({
  selector: 'app-platform-status',
  template: `
    <section>
      <p>Screen: {{ screenSize() }}</p>
      <p>Mobile layout: {{ isMobileLayout() ? 'yes' : 'no' }}</p>
      <p>Direction: {{ direction() }}</p>
      <p>Theme: {{ themeMode() }}</p>

      <button type="button" (click)="setTheme('light')">Light</button>
      <button type="button" (click)="setTheme('dark')">Dark</button>
      <button type="button" (click)="setTheme('system')">System</button>
    </section>
  `,
})
export class PlatformStatusComponent {
  private platform = inject(AXPlatform);

  protected themeMode = this.platform.themeMode;
  protected direction = signal(this.platform.isRtl() ? 'rtl' : 'ltr');
  protected screenSize = signal('5XL');
  protected isMobileLayout = computed(() => this.screenSize() === 'SM');

  constructor() {
    afterNextRender(() => {
      this.platform.autoDetectThemeMode();
      this.syncScreenSize();
    });

    this.platform.resize
      .pipe(takeUntilDestroyed())
      .subscribe(() => this.syncScreenSize());

    this.platform.directionChange
      .pipe(takeUntilDestroyed())
      .subscribe((event) => this.direction.set(event.data ?? 'ltr'));
  }

  protected setTheme(mode: AXThemeMode) {
    this.platform.setThemeMode(mode);
  }

  private syncScreenSize() {
    this.screenSize.set(this.platform.screenSize);
  }
}

import { Component, inject } from '@angular/core';
import { AXPlatform, AXThemeMode } from '@acorex/core/platform';

@Component({
  selector: 'app-theme-toggle',
  template: `
    <button type="button" (click)="cycleTheme()">
      Theme: {{ currentTheme }}
    </button>
  `,
})
export class ThemeToggleComponent {
  private platform = inject(AXPlatform);
  currentTheme: AXThemeMode = 'system';

  constructor() {
    this.platform.themeMode$.subscribe((mode) => {
      this.currentTheme = mode;
    });
  }

  cycleTheme() {
    const mode = this.platform.themeMode();
    if (mode.includes('dark')) {
      this.platform.setThemeMode('light');
    } else if (mode.includes('light')) {
      this.platform.setThemeMode('dark');
    } else {
      this.platform.setThemeMode('system');
    }
  }

  setLight() { this.platform.switchLightMode(); }
  setDark() { this.platform.switchDarkMode(); }
  setSystem() { this.platform.switchSystemMode(); }
}

import { inject } from '@angular/core';
import { AXPlatform } from '@acorex/core/platform';

const platform = inject(AXPlatform);

// Platforms
platform.is('Mobile');   // coarse pointer (touch device)
platform.is('Desktop');  // not mobile
platform.is('Android');
platform.is('iOS');

// Browsers
platform.is('Chrome');
platform.is('Safari');
platform.is('Firefox');
platform.is('Edge');

// Technologies
platform.is('PWA');      // standalone display mode
platform.is('Hybrid');   // Cordova / Capacitor
platform.is('Electron');

// Screen breakpoints (max-width media queries)
platform.is('SM');  // <= 640px  — used as "mobile" across AcoreX
platform.is('MD');  // <= 768px
platform.is('LG');  // <= 1024px

console.log(platform.screenSize); // e.g. 'MD', 'XL', '5XL'

import { inject } from '@angular/core';
import { AXPopupService } from '@acorex/components/popup';
import { AXPlatform } from '@acorex/core/platform';

async function openSettingsPopup(component: unknown) {
  const popup = inject(AXPopupService);
  const platform = inject(AXPlatform);

  await popup.open(component, {
    title: 'Settings',
    size: platform.is('SM') ? 'full' : 'md',
  });
}

