import { Component, inject, signal } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { AXPlatform } from '@acorex/core/platform';

@Component({
  selector: 'app-layout',
  template: `<p>Direction: {{ direction() }}</p>`,
})
export class LayoutComponent {
  private platform = inject(AXPlatform);
  direction = signal('ltr');

  constructor() {
    this.platform.resize
      .pipe(takeUntilDestroyed())
      .subscribe(() => this.onWindowResize());

    this.platform.directionChange
      .pipe(takeUntilDestroyed())
      .subscribe((e) => this.direction.set(e.data ?? 'ltr'));

    this.platform.click
      .pipe(takeUntilDestroyed())
      .subscribe((e) => {
        // Global click handling (capture phase)
      });
  }

  private onWindowResize() {
    // --ax-vh CSS variable is updated automatically by AXPlatform
  }
}

import { isBrowser, isServer } from '@acorex/core/platform';

function getLanguage(): string {
  return isBrowser() ? navigator.language : 'en-US';
}

function saveToStorage(key: string, value: string) {
  if (!isBrowser()) return;
  localStorage.setItem(key, value);
}

